class Playground {
  async run(inputs) {
    const nums = inputs[0].split(',').map(x => parseInt(x.trim()));
    this.array.init(nums);
    this.log('Count frequency of each element using HashMap');
    await this.await();

    for (let i = 0; i < nums.length; i++) {
      const num = nums[i];
      this.ptr.set('i', i);
      this.array.highlight(i, '#3b82f6');
      this.log(`Processing: ${num}`);
      await this.await();

      if (this.hashmap.has(num)) {
        const count = this.hashmap.get(num);
        this.hashmap.put(num, count + 1);
        this.hashmap.highlight(num, '#f59e0b');
        this.log(`${num} seen before → count = ${count + 1}`);
      } else {
        this.hashmap.put(num, 1);
        this.hashmap.highlight(num, '#10b981');
        this.log(`First time seeing ${num} → count = 1`);
      }
      await this.await();

      this.array.highlight(i, '#10b981');
      await this.await();
    }

    this.ptr.remove('i');
    this.log('✅ Frequency count complete!');
    await this.await();

    // Find the most frequent element
    let maxCount = 0;
    let maxNum = null;
    for (let i = 0; i < nums.length; i++) {
      const num = nums[i];
      const count = this.hashmap.get(num);
      if (count > maxCount) {
        maxCount = count;
        maxNum = num;
      }
    }

    this.hashmap.highlight(maxNum, '#ec4899');
    this.log(`🏆 Most frequent: ${maxNum} appears ${maxCount} times`);
    await this.await();

    return maxNum;
  }
}
